INSERT INTO TB_MonsterDefinition (Code, Name, Level, ModelCode, HP, PhysicalAttack, PhysicalDefense, MagicDefense, HitValue, HitRateBase, DodgeValue, CritValue, WalkSpeed, PatrolRange, GuardRange, ChaseRange, ThreatAIMode, Species, Exp, PetExp, SkillsJson, ItemDropRuleJson, ExtraItemsJson, SayInIdleJson, SayInBattleJson, AtPlace) VALUES ('g0080', N'Planta de Orvalho Silvestre', 8, 'c12', 412, 10, 42, 52, 1253, 0.5, 17, 11, 100, 200, 1500, 1000, 0, 1, 15, 9, N'["g00800"]', N'{"dropGroups": ["py0010", "pw0080", "aa0088"], "specialDrop": {"chance": 0, "multiplier": 1}}', N'[{"chance": 0.001, "itemCode": "qg0080"}]', N'["Pressione [Espaço] para auto-saquear quaisquer itens do chão.", "Pressione [U] para sentar-se e recuperar sua saúde e mana.", "Quer conferir os atributos de outro jogador? Quer conferir o equipamento de outro jogador? Clique no jogador para ver as informações do personagem."]', N'["Veja como sou bonitinho... Você realmente quer me atacar?"]', '2896,808@a3');
INSERT INTO TB_MonsterDefinition (Code, Name, Level, ModelCode, HP, PhysicalAttack, PhysicalDefense, MagicDefense, HitValue, HitRateBase, DodgeValue, CritValue, WalkSpeed, PatrolRange, GuardRange, ChaseRange, ThreatAIMode, Species, Exp, PetExp, SkillsJson, ItemDropRuleJson, ExtraItemsJson, SayInIdleJson, SayInBattleJson, AtPlace) VALUES ('g0100', N'Ent', 10, 'c19', 742, 72, 72, 72, 338, 0.5, 2, 12, 80, 200, 1500, 1000, 0, 2, 19, 12, N'["g01000"]', N'{"dropGroups": ["py0010", "pw0110", "aa0088"], "specialDrop": {"chance": 0, "multiplier": 1}}', N'[{"chance": 0.001, "itemCode": "qg0100"}]', N'["Pressione [ESC] para desselecionar seu alvo atual ou cancelar a canalização de alguma habilidade.", ""]', N'["Eu tenho pele grossa. Não tenho medo de você!"]', '2352,2040@a4');
INSERT INTO TB_MonsterDefinition (Code, Name, Level, ModelCode, HP, PhysicalAttack, PhysicalDefense, MagicDefense, HitValue, HitRateBase, DodgeValue, CritValue, WalkSpeed, PatrolRange, GuardRange, ChaseRange, ThreatAIMode, Species, Exp, PetExp, SkillsJson, ItemDropRuleJson, ExtraItemsJson, SayInIdleJson, SayInBattleJson, AtPlace) VALUES ('g0110', N'Surgimento do Golem de Pedra', 11, 'c29', 848, 69, 83, 70, 510, 0.5, 10, 12, 90, 200, 1500, 1000, 0, 3, 23, 13, N'["g01100"]', N'{"dropGroups": ["py0010", "pw0110", "py1010", "aa0088"], "specialDrop": {"chance": 0, "multiplier": 1}}', N'[{"chance": 0.001, "itemCode": "qg0110"}]', N'["Pressione [,] para abrir o mapa mundial.", "Pressione [Espaço] para autossaquear quaisquer itens do chão.", "Clique em um ponto do minimapa para ser deslocado para aquela posição.", "Você pode clicar em itens sublinhados ou nomes de PNJ em sua janela de missões para ser movido automaticamente ao local da missão.", "Pressione [ESC] para desselecionar seu alvo atual ou cancelar a canalização de alguma habilidade."]', N'["Vou crescer e esmagar você!", "Não tenho ovos comigo! Não há itens de missão aqui!"]', '2576,1288@a4');
INSERT INTO TB_MonsterDefinition (Code, Name, Level, ModelCode, HP, PhysicalAttack, PhysicalDefense, MagicDefense, HitValue, HitRateBase, DodgeValue, CritValue, WalkSpeed, PatrolRange, GuardRange, ChaseRange, ThreatAIMode, Species, Exp, PetExp, SkillsJson, ItemDropRuleJson, ExtraItemsJson, SayInIdleJson, SayInBattleJson, AtPlace) VALUES ('g0130', N'Peste Duende', 14, 'c22', 1147, 85, 72, 72, 865, 0.5, 23, 14, 100, 200, 1500, 1000, 0, 2, 30, 16, N'["g01300"]', N'{"dropGroups": ["py0010", "pw0140", "py1010", "aa0088"], "specialDrop": {"chance": 0, "multiplier": 1}}', N'[{"chance": 0.001, "itemCode": "qg0130"}]', N'["Pressione [U] para sentar-se e recuperar sua saúde e mana.", "Os nomes de áreas encontram-se acima do minimapa. Um nome branco significa que a área é segura, enquanto um nome vermelho significa que a área é JxJ."]', N'["Você ousa entrar em nossas terras? Agora você pagará!"]', '3536,3432@b1');
INSERT INTO TB_MonsterDefinition (Code, Name, Level, ModelCode, HP, PhysicalAttack, PhysicalDefense, MagicDefense, HitValue, HitRateBase, DodgeValue, CritValue, WalkSpeed, PatrolRange, GuardRange, ChaseRange, ThreatAIMode, Species, Exp, PetExp, SkillsJson, ItemDropRuleJson, ExtraItemsJson, SayInIdleJson, SayInBattleJson, AtPlace) VALUES ('g0150', N'Vigilante da Fenda', 15, 'c01', 1246, 87, 72, 72, 1305, 0.5, 72, 22, 130, 200, 1500, 1000, 0, 0, 37, 19, N'["g01500"]', N'{"dropGroups": ["py0010", "pw0140", "py1010", "aa0088"], "specialDrop": {"chance": 0, "multiplier": 1}}', N'[{"chance": 0.001, "itemCode": "qg0150"}]', N'["Pressione [Z] para subir em sua montaria.", "Mantenha [CTRL] pressionado e clique com o botão esquerdo para forçar o movimento do seu personagem, ignorando seu alvo atual.", "Pressione [ESC] para desselecionar seu alvo atual ou cancelar a canalização de alguma habilidade."]', N'["Explique! Já!!! Você quer morrer? Ou apenas evitar viver?"]', '1488,808@b3');
