INSERT INTO TB_MonsterDefinition (Code, Name, Level, ModelCode, HP, PhysicalAttack, PhysicalDefense, MagicDefense, HitValue, HitRateBase, DodgeValue, CritValue, WalkSpeed, PatrolRange, GuardRange, ChaseRange, ThreatAIMode, Species, Exp, PetExp, SkillsJson, ItemDropRuleJson, ExtraItemsJson, SayInIdleJson, SayInBattleJson, AtPlace) VALUES ('g0200', N'Nepenthene', 20, 'c12', 2185, 10, 80, 100, 1343, 0.5, 29, 17, 100, 200, 1500, 1000, 0, 1, 70, 26, N'["g02000"]', N'{"dropGroups": ["py0020", "pw0200", "py1020", "aa0088"], "specialDrop": {"chance": 0, "multiplier": 1}}', N'[{"chance": 0.001, "itemCode": "qg0200"}]', N'["Enquanto estiver em Modo Mau, você pode atacar outros jogadores em certas áreas.", "Clicar com o botão esquerdo em um jogador mantendo [SHIFT] pressionado enquanto estiver em Modo Mau permitirá que você visualize o jogador sem atacá-lo.", "Você já entendeu? Agora você pode atacar outros jogadores, se entrar em ''Modo Mau'', se assim desejar!"]', N'["Você veio me trazer comida?"]', '3216,3000@b4');
